const teamMap = {
  'Mexico': 'Mexiko', 'Korea Republic': 'Südkorea', 'South Korea': 'Südkorea',
  'Czech Republic': 'Tschechien', 'Czechia': 'Tschechien', 'South Africa': 'Südafrika',
  'Canada': 'Kanada', 'Bosnia and Herzegovina': 'Bosnien-Herzegowina',
  'Bosnia-Herzegovina': 'Bosnien-Herzegowina', 'Qatar': 'Katar', 'Switzerland': 'Schweiz',
  'Brazil': 'Brasilien', 'Morocco': 'Marokko', 'Haiti': 'Haiti', 'Scotland': 'Schottland',
  'USA': 'USA', 'United States': 'USA', 'Paraguay': 'Paraguay',
  'Australia': 'Australien', 'Turkey': 'Türkei', 'Türkiye': 'Türkei',
  'Germany': 'Deutschland', 'Curaçao': 'Curaçao', "Côte d'Ivoire": 'Elfenbeinküste',
  'Ivory Coast': 'Elfenbeinküste', 'Ecuador': 'Ecuador', 'Netherlands': 'Niederlande',
  'Japan': 'Japan', 'Sweden': 'Schweden', 'Tunisia': 'Tunesien', 'Belgium': 'Belgien',
  'Egypt': 'Ägypten', 'Iran': 'Iran', 'IR Iran': 'Iran', 'New Zealand': 'Neuseeland',
  'Spain': 'Spanien', 'Cape Verde': 'Kap Verde', 'Cabo Verde': 'Kap Verde',
  'Saudi Arabia': 'Saudi-Arabien', 'Uruguay': 'Uruguay', 'France': 'Frankreich',
  'Senegal': 'Senegal', 'Iraq': 'Irak', 'Norway': 'Norwegen', 'Argentina': 'Argentinien',
  'Algeria': 'Algerien', 'Austria': 'Österreich', 'Jordan': 'Jordanien',
  'Portugal': 'Portugal', 'Congo DR': 'DR Kongo', 'DR Congo': 'DR Kongo',
  'Democratic Republic of Congo': 'DR Kongo', 'Uzbekistan': 'Usbekistan',
  'Colombia': 'Kolumbien', 'England': 'England', 'Croatia': 'Kroatien',
  'Ghana': 'Ghana', 'Panama': 'Panama',
};

const matches = $input.first().json.matches || [];
const result = [];
for (const m of matches) {
  if (m.status !== 'FINISHED') continue;
  const score = m.score?.fullTime;
  if (score?.home === null || score?.home === undefined) continue;
  const home = teamMap[m.homeTeam?.name] || m.homeTeam?.name;
  const away = teamMap[m.awayTeam?.name] || m.awayTeam?.name;
  result.push({ home, away, home_score: score.home, away_score: score.away });
}
return [{ json: { matches: result, count: result.length } }];

